// GET /api/posts?limit=20&after=<cursor>

// --- Cursor helpers ---

// Encode the compound cursor (created_at, id) as an opaque base64 JSON string.
function encodeCursor(row) {
    const payload = {
        created_at: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    };
    return Buffer.from(JSON.stringify(payload), 'utf8').toString('base64url');
}

// Decode and validate a cursor. Throws on anything malformed so the
// caller can return a 400.
function decodeCursor(cursor) {
    let parsed;
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        parsed = JSON.parse(json);
    } catch {
        throw new Error('INVALID_CURSOR');
    }

    if (
        !parsed ||
        typeof parsed !== 'object' ||
        typeof parsed.created_at !== 'string' ||
        parsed.id === undefined ||
        parsed.id === null
    ) {
        throw new Error('INVALID_CURSOR');
    }

    // Reject an unparseable timestamp.
    if (Number.isNaN(Date.parse(parsed.created_at))) {
        throw new Error('INVALID_CURSOR');
    }

    return { created_at: parsed.created_at, id: parsed.id };
}

// --- Handler ---

async function getPosts(req, res) {
    // Clamp limit to a sane range to protect the DB.
    let limit = parseInt(req.query.limit, 10) || 20;
    limit = Math.max(1, Math.min(limit, 100));

    const params = [];
    let whereClause = 'WHERE published = true';

    // Only add the cursor predicate when an `after` cursor is supplied.
    if (req.query.after) {
        let cursor;
        try {
            cursor = decodeCursor(req.query.after);
        } catch {
            return res.status(400).json({ error: 'Invalid cursor' });
        }

        // Sort is (created_at DESC, id DESC), so "after" means strictly
        // less than the cursor in that ordering. Row-value comparison
        // expresses the compound keyset condition cleanly:
        //   (created_at, id) < (cursor.created_at, cursor.id)
        params.push(cursor.created_at, cursor.id);
        whereClause += ` AND (created_at, id) < ($1, $2)`;
    }

    // LIMIT N+1 trick: fetch one extra row to detect whether more exist.
    params.push(limit + 1);
    const limitParamIndex = params.length;

    const result = await db.query(
        `SELECT id, title, content, author_id, created_at
         FROM posts
         ${whereClause}
         ORDER BY created_at DESC, id DESC
         LIMIT $${limitParamIndex}`,
        params
    );

    const rows = result.rows;
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor = hasMore
        ? encodeCursor(posts[posts.length - 1])
        : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}

module.exports = { getPosts, encodeCursor, decodeCursor };
```

## Notes on key decisions

- **Row-value comparison `(created_at, id) < ($1, $2)`** — Postgres evaluates this as a true lexicographic tuple comparison, which exactly matches the `ORDER BY created_at DESC, id DESC` ordering. This is cleaner and less error-prone than the manual expansion `created_at < $1 OR (created_at = $1 AND id < $2)`, and it lets Postgres use a composite index on `(created_at DESC, id DESC)` efficiently.
- **`base64url`** — used instead of plain `base64` so the cursor is URL-safe (no `+`, `/`, or `=` that need escaping in a query string).
- **Validation** — `decodeCursor` rejects bad base64, bad JSON, missing fields, and unparseable timestamps, all surfaced as a `400`. Note that an `id` of `0` is still valid (the check guards against `undefined`/`null`, not falsiness).
- **Index recommendation** — for this to be fast, ensure: `CREATE INDEX ON posts (created_at DESC, id DESC) WHERE published = true;` (a partial index matching the `published = true` filter).

## Why cursor-based pagination is superior here

1. **Constant performance at any depth.** `OFFSET 1000000` forces Postgres to scan and discard a million rows before returning results — cost grows linearly with page depth. A keyset `WHERE (created_at, id) < (...)` seeks directly into the index and reads only the rows you return, so page 50,000 is as fast as page 1.
2. **Stable results under concurrent writes.** With offsets, a post inserted or deleted while a user paginates shifts every subsequent row, causing skipped or duplicated items across pages. The cursor anchors to a specific `(created_at, id)` position, so new inserts don't disturb the user's place.
3. **No expensive COUNT.** `SELECT COUNT(*)` over a large table is a full scan/index scan on every request. Dropping it (as required) removes that cost; `hasMore` from the N+1 trick gives the client what it actually needs to drive "load more" UIs.

The trade-off: you lose random access to an arbitrary page number (no "jump to page 7") — which is exactly the right trade for an infinite-scroll / "load more" feed sorted by recency.

