// ─── Cursor helpers ───────────────────────────────────────────────────────────

/**
 * Encode a (created_at, id) pair into an opaque, URL-safe base64 cursor string.
 * created_at is normalised to an ISO string so it round-trips through JSON safely.
 */
function encodeCursor(createdAt, id) {
    const payload = JSON.stringify({
        created_at: createdAt instanceof Date ? createdAt.toISOString() : createdAt,
        id,
    });
    return Buffer.from(payload).toString('base64url'); // URL-safe variant — no +/= padding issues
}

/**
 * Decode a base64 cursor back to { created_at, id }.
 * Throws a descriptive Error on any malformed input; callers should catch and return 400.
 */
function decodeCursor(cursor) {
    let payload;
    try {
        payload = JSON.parse(Buffer.from(cursor, 'base64url').toString('utf8'));
    } catch {
        throw new Error('Cursor is not valid base64-encoded JSON.');
    }

    if (typeof payload !== 'object' || payload === null) {
        throw new Error('Cursor payload must be a JSON object.');
    }
    if (!payload.created_at || payload.id == null) {
        throw new Error('Cursor is missing required fields (created_at, id).');
    }

    // Coerce id to a number for safety
    const id = Number(payload.id);
    if (!Number.isFinite(id)) {
        throw new Error('Cursor id field is not a valid number.');
    }

    return { created_at: payload.created_at, id };
}


// ─── Route handler ────────────────────────────────────────────────────────────

// GET /api/posts?limit=20&after=<cursor>
async function getPosts(req, res) {
    // ── 1. Parse & validate inputs ───────────────────────────────────────────
    const limit = Math.min(Math.max(parseInt(req.query.limit) || 20, 1), 100);
    const after = req.query.after ?? null;

    // ── 2. Optionally decode the incoming cursor ──────────────────────────────
    let cursor = null;
    if (after !== null) {
        try {
            cursor = decodeCursor(after);
        } catch (err) {
            return res.status(400).json({ error: `Invalid cursor: ${err.message}` });
        }
    }

    // ── 3. Build query — no OFFSET, no COUNT ─────────────────────────────────
    //
    // Sort order: created_at DESC, id DESC
    // "After the cursor" means a row whose (created_at, id) pair is *less than*
    // the cursor's in that descending ordering:
    //
    //   created_at is strictly older  →  definitely later in the result set
    //   OR same created_at but smaller id  →  also later in the result set
    //
    // Using the N+1 trick: fetch one extra row to detect whether another page
    // exists without an expensive COUNT(*).

    let queryText;
    let queryParams;

    if (cursor === null) {
        // First page — no cursor filter
        queryText = `
            SELECT id, title, content, author_id, created_at
            FROM   posts
            WHERE  published = true
            ORDER  BY created_at DESC, id DESC
            LIMIT  $1
        `;
        queryParams = [limit + 1];
    } else {
        queryText = `
            SELECT id, title, content, author_id, created_at
            FROM   posts
            WHERE  published = true
              AND  (
                       created_at < $2
                   OR (created_at = $2 AND id < $3)
                   )
            ORDER  BY created_at DESC, id DESC
            LIMIT  $1
        `;
        queryParams = [limit + 1, cursor.created_at, cursor.id];
    }

    // ── 4. Execute & interpret the N+1 result ────────────────────────────────
    const result = await db.query(queryText, queryParams);
    const rows = result.rows;

    const hasMore = rows.length === limit + 1;
    const posts   = hasMore ? rows.slice(0, limit) : rows;  // drop the sentinel

    // The next cursor points at the last row we're actually returning so that
    // the following request picks up exactly where we left off.
    const nextCursor = hasMore
        ? encodeCursor(posts[posts.length - 1].created_at, posts[posts.length - 1].id)
        : null;

    // ── 5. Respond ────────────────────────────────────────────────────────────
    return res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,   // null when this is the last page
            limit,
        },
    });
}
```

---

## How the cursor condition works

The sort is `ORDER BY created_at DESC, id DESC`. The last row on page N has some `(T, I)`. To continue from that point on page N+1, we need all rows that would appear *after* it in that ordering — meaning rows with a **smaller** `(created_at, id)` pair:

```
(created_at < T)                        -- strictly older post: always after
OR (created_at = T AND id < I)          -- same timestamp, smaller id: also after
```

This is a standard **row-value comparison** expressed manually because PostgreSQL's `ROW(a, b) < ROW($1, $2)` on mixed-type columns can confuse the query planner. Explicit form keeps the index on `(created_at DESC, id DESC)` usable.

---

## Why cursor pagination is superior here

| Concern | Offset | Cursor |
|---|---|---|
| **Consistency under inserts/deletes** | Rows shift — you skip or duplicate items as the table changes | Stable — the WHERE clause anchors to a real row position |
| **Performance at depth** | `OFFSET 50000` forces the DB to read and discard 50 000 rows every time | No scan overhead — the index seek lands directly at the cursor row |
| **Expensive COUNT** | Needed for "page X of Y" UI; full table scan on every request | Eliminated entirely (N+1 trick gives `hasMore` cheaply) |
| **Scalability** | Degrades linearly with page depth | Constant cost regardless of how deep the client has scrolled |

The trade-off is that you lose **random page access** (you can't jump to "page 47"), but for feed-style infinite-scroll UIs — which is the predominant use case for this sort of `created_at DESC` listing — that's rarely needed.

